const data = $input.first().json;

if (!data.templatePath) {
  throw new Error('Parámetro requerido: templatePath');
}
if (!data.variables || typeof data.variables !== 'object') {
  throw new Error('Parámetro requerido: variables (objeto con claves y valores)');
}

let templatePath = data.templatePath;
if (!templatePath.startsWith('/workspace/')) {
  templatePath = '/workspace/' + templatePath;
}

return [{ json: { templatePath, variables: data.variables } }];

let template = $('Leer Template').first().json.data;
const variables = $('Validar Parámetros').first().json.variables;

for (const [key, value] of Object.entries(variables)) {
  const placeholder = new RegExp(`\\{\\{${key}\\}\\}`, 'g');
  template = template.replace(placeholder, value || '');
}

return [{ json: { content: template, variables } }];
